const orgs = $input.all().map(i => i.json);
const rewards = [];

for (const org of orgs) {
  const daysActive = Number(org.days_active || 0);
  const totalEvents = Number(org.total_events || 0);
  const csiScore = Number(org.csi_score || 0);

  // Milestone: 100 total events
  if (totalEvents >= 100 && totalEvents < 200) {
    rewards.push({ json: { organization_id: org.organization_id, name: org.name, milestone: '100_events', dimension: 'ai_generations', quantity: 25, reason: '100 usage events milestone' } });
  }
  // Milestone: 6-month anniversary (180 days)
  if (daysActive >= 180 && daysActive < 187) {
    rewards.push({ json: { organization_id: org.organization_id, name: org.name, milestone: '6_month', dimension: 'ai_generations', quantity: 50, reason: '6-month anniversary' } });
  }
  // Milestone: CSI 90+
  if (csiScore >= 90) {
    rewards.push({ json: { organization_id: org.organization_id, name: org.name, milestone: 'csi_90', dimension: 'ai_generations', quantity: 30, reason: 'CSI score 90+' } });
  }
}

if (rewards.length === 0) return [{ json: { no_milestones: true } }];
return rewards;
